    commandProperties = {
        @HystrixProperty(
            name = "execution.isolation.strategy",
            value = "SEMAPHORE"
        ),
        @HystrixProperty(
            name = "execution.isolation.thread.timeoutInMilliseconds",
            value = "1000"
        )
    }
)
